from datetime import datetime, date
from dataclasses import dataclass

@dataclass
class VersionedEndpoint:
    version: str          # e.g. "v1", "v2"
    status: str           # "current", "deprecated", "sunset"
    sunset_date: date | None
    successor_version: str | None

    def sunset_header(self) -> str | None:
        if self.sunset_date:
            return self.sunset_date.strftime("%a, %d %b %Y 00:00:00 GMT")
        return None

    def deprecation_header(self) -> str | None:
        if self.status == "deprecated" and self.successor_version:
            return f'rel="successor-version"; url="/api/{self.successor_version}/query"'
        return None

# FastAPI middleware example — inject versioning headers
from fastapi import Request, Response

ENDPOINTS = {
    "v1": VersionedEndpoint("v1", "deprecated", date(2026, 12, 31), "v2"),
    "v2": VersionedEndpoint("v2", "current", None, None),
}

async def versioning_middleware(request: Request, call_next):
    version = request.path_params.get("version", "v2")
    ep = ENDPOINTS.get(version)
    response: Response = await call_next(request)
    if ep:
        if ep.sunset_header():
            response.headers["Sunset"] = ep.sunset_header()
        if ep.deprecation_header():
            response.headers["Deprecation"] = "true"
            response.headers["Link"] = ep.deprecation_header()
    return response
